  ('social-worker-moex-07871', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在下列數值的排序中，那一個是中位數？ 8, 12, 9, 15, 17, 11, 13, 14, 7', '["12", "17", "4.5", "5"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
